//! TypeScript type auto-export.
//!
//! Types that derive `ApiSchema`, `AppEnum`, or `foundry::TS` are automatically
//! registered for TypeScript export via the `inventory` crate.
//!
//! `AppEnum` types also export runtime metadata:
//! ```ts
//! export type CountryStatus = "enabled" | "disabled";
//! export const CountryStatusValues = freezeCountryStatusEnumValue(["enabled", "disabled"] as const);
//! export const CountryStatusOptions = freezeCountryStatusEnumValue([
//!   { value: "enabled", labelKey: "enum.country_status.enabled" },
//!   { value: "disabled", labelKey: "enum.country_status.disabled" },
//! ] as const);
//! export function isCountryStatus(value: unknown): value is CountryStatus;
//! export function getCountryStatusLabelKey(value: CountryStatus): string;
//! export const CountryStatusKeys = freezeCountryStatusEnumValue({ enabled: "enabled", disabled: "disabled" } as const);
//! ```

