#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum RouteManifestSchemaWrapper {
    Array,
    Map,
    Nullable,
    PaginatedResponse,
    CursorPaginated,
    Collection,
}

impl RouteManifestSchemaWrapper {
    const ALL: [Self; 6] = [
        Self::Array,
        Self::Map,
        Self::Nullable,
        Self::PaginatedResponse,
        Self::CursorPaginated,
        Self::Collection,
    ];

    fn name(self) -> &'static str {
        match self {
            Self::Array => "Array",
            Self::Map => "Map",
            Self::Nullable => "Nullable",
            Self::PaginatedResponse => "PaginatedResponse",
            Self::CursorPaginated => "CursorPaginated",
            Self::Collection => "Collection",
        }
    }
}

#[derive(Clone, Copy)]
enum BarrelExportKind {
    Value,
    Type,
}

#[derive(Clone, Copy)]
struct BarrelExport {
    name: &'static str,
    kind: BarrelExportKind,
}

#[derive(Clone, Copy)]
enum FrameworkTypeScriptModuleKind {
    AppManifest,
    AuthManifest,
    AuditManifest,
    LoggingManifest,
    RouteManifest,
    HttpManifest,
    WebSocketChannelManifest,
    EventManifest,
    JobManifest,
    CommandManifest,
    ScheduleManifest,
    ValidationRuleManifest,
    PluginManifest,
    StorageManifest,
    EmailManifest,
    I18nManifest,
    ReadinessManifest,
    SettingManifest,
    CacheManifest,
    DatabaseManifest,
    ObservabilityManifest,
    DatatableManifest,
    NotificationManifest,
    EndpointRuntime,
}

struct FrameworkTypeScriptModule {
    kind: FrameworkTypeScriptModuleKind,
    module: &'static str,
    file: &'static str,
    owner: &'static str,
    exports: &'static [BarrelExport],
}

struct FrameworkTypeScriptModuleRenderContext<'a> {
    app: &'a AppManifestDescriptor,
    auth_guards: &'a [AuthGuardDescriptor],
    auth_policies: &'a [AuthPolicyDescriptor],
    authenticatables: &'a [AuthenticatableDescriptor],
    auth_runtime: &'a AuthRuntimeManifestDescriptor,
    audit: &'a AuditManifestDescriptor,
    logging: &'a LoggingManifestDescriptor,
    routes: &'a [RouteManifestEntry],
    http: &'a HttpManifestDescriptor,
    websocket_channels: &'a [WebSocketChannelDescriptor],
    websocket_runtime: &'a WebSocketRuntimeManifestDescriptor,
    websocket_payloads: &'a BTreeMap<WebSocketPayloadKey, &'a TsWebSocketPayload>,
    events: &'a [EventDescriptor],
    event_payloads: &'a BTreeMap<String, &'a TsEventPayload>,
    jobs: &'a [JobDescriptor],
    job_runtime: &'a JobRuntimeManifestDescriptor,
    job_payloads: &'a BTreeMap<String, &'a TsJobPayload>,
    commands: &'a [CommandDescriptor],
    schedules: &'a [ScheduleDescriptor],
    scheduler_runtime: &'a SchedulerRuntimeManifestDescriptor,
    validation_rules: &'a [ValidationRuleDescriptor],
    plugins: &'a [PluginDescriptor],
    storage_disks: &'a [StorageDiskDescriptor],
    storage_runtime: &'a StorageRuntimeManifestDescriptor,
    email_mailers: &'a [EmailMailerDescriptor],
    email_runtime: &'a EmailRuntimeManifestDescriptor,
    i18n: &'a I18nManifestDescriptor,
    readiness_probes: &'a [ReadinessProbeDescriptor],
    settings: &'a BTreeMap<&'static str, SettingManifestDescriptor>,
    cache: &'a CacheManifestDescriptor,
    database: &'a DatabaseManifestDescriptor,
    observability: &'a ObservabilityManifestDescriptor,
    datatables: &'a [DatatableDescriptor],
    datatable_runtime: &'a DatatableRuntimeManifestDescriptor,
    notifications: &'a BTreeMap<&'static str, &'a TsNotification>,
    exported_types: &'a BTreeMap<String, String>,
    app_timezone: &'a str,
}

impl FrameworkTypeScriptModule {
    fn render(&self, context: &FrameworkTypeScriptModuleRenderContext<'_>) -> Result<String> {
        match self.kind {
            FrameworkTypeScriptModuleKind::AppManifest => render_app_manifest(context.app),
            FrameworkTypeScriptModuleKind::AuthManifest => render_auth_manifest(
                context.auth_guards,
                context.auth_policies,
                context.authenticatables,
                context.auth_runtime,
            ),
            FrameworkTypeScriptModuleKind::AuditManifest => render_audit_manifest(context.audit),
            FrameworkTypeScriptModuleKind::LoggingManifest => {
                render_logging_manifest(context.logging)
            }
            FrameworkTypeScriptModuleKind::RouteManifest => render_route_manifest(context.routes),
            FrameworkTypeScriptModuleKind::HttpManifest => render_http_manifest(context.http),
            FrameworkTypeScriptModuleKind::WebSocketChannelManifest => {
                render_websocket_channel_manifest_with_payloads(
                    context.websocket_channels,
                    context.websocket_runtime,
                    context.websocket_payloads,
                    context.exported_types,
                )
            }
            FrameworkTypeScriptModuleKind::EventManifest => render_event_manifest(
                context.events,
                context.event_payloads,
                context.exported_types,
            ),
            FrameworkTypeScriptModuleKind::JobManifest => render_job_manifest(
                context.jobs,
                context.job_runtime,
                context.job_payloads,
                context.exported_types,
            ),
            FrameworkTypeScriptModuleKind::CommandManifest => {
                render_command_manifest(context.commands)
            }
            FrameworkTypeScriptModuleKind::ScheduleManifest => {
                render_schedule_manifest(context.schedules, context.scheduler_runtime)
            }
            FrameworkTypeScriptModuleKind::ValidationRuleManifest => {
                render_validation_rule_manifest(context.validation_rules)
            }
            FrameworkTypeScriptModuleKind::PluginManifest => {
                render_plugin_manifest(context.plugins)
            }
            FrameworkTypeScriptModuleKind::StorageManifest => {
                render_storage_manifest(context.storage_disks, context.storage_runtime)
            }
            FrameworkTypeScriptModuleKind::EmailManifest => {
                render_email_manifest(context.email_mailers, context.email_runtime)
            }
            FrameworkTypeScriptModuleKind::I18nManifest => render_i18n_manifest(context.i18n),
            FrameworkTypeScriptModuleKind::ReadinessManifest => {
                render_readiness_manifest(context.readiness_probes)
            }
            FrameworkTypeScriptModuleKind::SettingManifest => {
                render_setting_manifest(context.settings)
            }
            FrameworkTypeScriptModuleKind::CacheManifest => render_cache_manifest(context.cache),
            FrameworkTypeScriptModuleKind::DatabaseManifest => {
                render_database_manifest(context.database)
            }
            FrameworkTypeScriptModuleKind::ObservabilityManifest => {
                render_observability_manifest(context.observability)
            }
            FrameworkTypeScriptModuleKind::DatatableManifest => {
                render_datatable_manifest(context.datatables, context.datatable_runtime)
            }
            FrameworkTypeScriptModuleKind::NotificationManifest => {
                render_notification_manifest(context.notifications, context.exported_types)
            }
            FrameworkTypeScriptModuleKind::EndpointRuntime => {
                Ok(render_endpoint_runtime(context.app_timezone))
            }
        }
    }
}

struct DynamicBarrelExport {
    name: String,
    kind: BarrelExportKind,
}

const fn barrel_value(name: &'static str) -> BarrelExport {
    BarrelExport {
        name,
        kind: BarrelExportKind::Value,
    }
}

const fn barrel_type(name: &'static str) -> BarrelExport {
    BarrelExport {
        name,
        kind: BarrelExportKind::Type,
    }
}

