pub trait TsValidationSchemaProvider {
    fn ts_validation_schema() -> TsValidationSchema;
}

#[derive(Clone, Debug, Default, PartialEq)]
pub struct TsValidationSchema {
    pub deny_unknown_fields: bool,
    pub known_fields: Vec<String>,
    pub field_value_kinds: Vec<TsValidationFieldValueKindEntry>,
    pub rules: Vec<TsValidationRule>,
    pub fields: Vec<TsValidationField>,
    pub messages: Vec<TsValidationMessage>,
    pub attributes: Vec<TsValidationAttribute>,
}

impl TsValidationSchema {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn deny_unknown_fields(mut self) -> Self {
        self.deny_unknown_fields = true;
        self
    }

    pub fn deny_unknown_fields_with_known_fields<I, F>(mut self, fields: I) -> Self
    where
        I: IntoIterator<Item = F>,
        F: Into<String>,
    {
        self.deny_unknown_fields = true;
        self.known_fields(fields)
    }

    pub fn known_field(mut self, field: impl Into<String>) -> Self {
        push_unique_string(&mut self.known_fields, field.into());
        self
    }

    pub fn known_fields<I, F>(mut self, fields: I) -> Self
    where
        I: IntoIterator<Item = F>,
        F: Into<String>,
    {
        for field in fields {
            push_unique_string(&mut self.known_fields, field.into());
        }
        self
    }

    pub fn field_value_kind(
        mut self,
        field: impl Into<String>,
        kind: TsValidationFieldValueKind,
    ) -> Self {
        upsert_validation_field_value_kind(&mut self.field_value_kinds, field.into(), kind);
        self
    }

    pub fn rule(mut self, rule: TsValidationRule) -> Self {
        push_unique_validation_rule(&mut self.rules, rule);
        self
    }

    pub fn field<I>(mut self, name: impl Into<String>, rules: I) -> Self
    where
        I: IntoIterator<Item = TsValidationRule>,
    {
        let name = name.into();
        let rules = rules.into_iter().collect::<Vec<_>>();
        if let Some(field) = self.fields.iter_mut().find(|field| field.name == name) {
            field.rules.extend(rules);
        } else {
            self.fields.push(TsValidationField::new(name, rules));
        }
        self
    }

    pub fn message(
        mut self,
        field: impl Into<String>,
        rule: impl Into<String>,
        message: impl Into<String>,
    ) -> Self {
        let field = field.into();
        let rule = rule.into();
        let message = message.into();
        if let Some(existing) = self
            .messages
            .iter_mut()
            .find(|entry| entry.field == field && entry.rule == rule)
        {
            existing.message = message;
        } else {
            self.messages.push(TsValidationMessage {
                field,
                rule,
                message,
            });
        }
        self
    }

    pub fn attribute(mut self, field: impl Into<String>, name: impl Into<String>) -> Self {
        let field = field.into();
        let name = name.into();
        if let Some(existing) = self
            .attributes
            .iter_mut()
            .find(|entry| entry.field == field)
        {
            existing.name = name;
        } else {
            self.attributes.push(TsValidationAttribute { field, name });
        }
        self
    }
}

#[derive(Clone, Copy, Debug, Default, PartialEq, Eq)]
pub enum TsValidationFieldValueKind {
    #[default]
    Scalar,
    Array,
    Map,
    Json,
    File,
    Nested,
}

impl TsValidationFieldValueKind {
    pub fn as_str(self) -> &'static str {
        match self {
            Self::Scalar => "scalar",
            Self::Array => "array",
            Self::Map => "map",
            Self::Json => "json",
            Self::File => "file",
            Self::Nested => "nested",
        }
    }

    fn validation_literal(self) -> &'static str {
        self.as_str()
    }
}

