    fn field_list_rule<I, V>(code: impl Into<String>, fields: I) -> Self
    where
        I: IntoIterator<Item = V>,
        V: ToString,
    {
        let mut rule = Self::new(code);
        for field in fields {
            push_unique_string(&mut rule.values, field.to_string());
        }
        rule.params
            .insert("other".to_string(), rule.values.join(", "));
        rule
    }

    fn field_ref_rule(code: impl Into<String>, other: impl Into<String>) -> Self {
        Self::new(code).param("other", other.into())
    }

