fn register_barrel_export_owner(
    owners: &mut BTreeMap<String, String>,
    name: &str,
    owner: String,
) -> Result<()> {
    if let Some(existing) = owners.get(name) {
        return Err(Error::message(format!(
            "{existing} and {owner} both export TypeScript name `{name}`; each generated barrel export must own a unique name"
        )));
    }

    owners.insert(name.to_string(), owner);
    Ok(())
}

fn route_helper_barrel_exports(name: &str) -> Vec<DynamicBarrelExport> {
    RouteHelperTypeScriptExports::new(name).barrel_exports()
}

fn planned_output_files(
    ts_type_files: &BTreeMap<&'static str, String>,
    app_enums: &BTreeMap<&'static str, EnumMeta>,
    route_helpers: &[PlannedRouteHelper<'_>],
) -> Result<BTreeSet<String>> {
    let mut files = BTreeSet::new();
    let mut owners = BTreeMap::<String, String>::new();

    for (name, file) in ts_type_files {
        register_output_file_owner(
            &mut owners,
            file,
            format!("TypeScript type export `{name}`"),
        )?;
    }
    for name in app_enums.keys() {
        register_output_file_owner(
            &mut owners,
            &format!("{name}.ts"),
            format!("AppEnum export `{name}`"),
        )?;
    }
    for module in FRAMEWORK_TYPESCRIPT_MODULES {
        register_output_file_owner(&mut owners, module.file, module.owner.to_string())?;
    }
    for helper in route_helpers {
        register_output_file_owner(
            &mut owners,
            &helper.file,
            format!("route endpoint helper `{}`", helper.route.id.as_str()),
        )?;
    }
    register_output_file_owner(
        &mut owners,
        "index.ts",
        "Foundry TypeScript barrel".to_string(),
    )?;

    files.extend(owners.into_keys());
    Ok(files)
}

fn register_output_file_owner(
    owners: &mut BTreeMap<String, String>,
    file: &str,
    owner: String,
) -> Result<()> {
    if let Some(existing) = owners.get(file) {
        return Err(Error::message(format!(
            "{existing} and {owner} both target generated TypeScript output path `{file}`; each generated artifact must own a unique .ts file"
        )));
    }

    owners.insert(file.to_string(), owner);
    Ok(())
}

fn ts_type_output_file(ts_type: &TsType) -> Result<String> {
    let path = (ts_type.output_path_fn)().ok_or_else(|| {
        Error::message(format!(
            "TypeScript export `{}` does not expose an output path",
            ts_type.name
        ))
    })?;
    let file = path.to_str().ok_or_else(|| {
        Error::message(format!(
            "TypeScript export `{}` output path must be valid UTF-8",
            ts_type.name
        ))
    })?;

    let Some(path) = safe_manifest_path_with_extension(file, "ts", true) else {
        return Err(Error::message(format!(
            "TypeScript export `{}` output path `{file}` must be a relative .ts path inside the generated types directory",
            ts_type.name
        )));
    };

    Ok(path.to_string_lossy().replace('\\', "/"))
}

fn ts_module_specifier(file: &str) -> Result<String> {
    let module = file.strip_suffix(".ts").ok_or_else(|| {
        Error::message(format!(
            "TypeScript barrel export path `{file}` must end with .ts"
        ))
    })?;
    Ok(format!("./{module}"))
}

fn clean_manifest_files(dir: &Path, output_files: &BTreeSet<String>) -> Result<()> {
    clean_generated_manifest_files(
        dir,
        TYPES_EXPORT_MANIFEST,
        output_files,
        "foundry.typescript",
        |file| safe_manifest_path_with_extension(file, "ts", true),
    )
}

fn write_export_manifest(dir: &Path, output_files: &BTreeSet<String>) -> Result<()> {
    write_manifest(dir, TYPES_EXPORT_MANIFEST, output_files)
}

fn collect_route_manifest(routes: &[RouteRegistrar]) -> Result<Vec<RouteManifestEntry>> {
    let mut registrar = HttpRegistrar::new();
    for route in routes {
        route(&mut registrar)?;
    }
    registrar.collect_route_manifest()
}

fn collect_websocket_channel_manifest(
    websocket_routes: &[WebSocketRouteRegistrar],
) -> Result<Vec<WebSocketChannelDescriptor>> {
    let registrar = crate::websocket::build_registrar(websocket_routes)?;
    Ok(crate::websocket::WebSocketChannelRegistry::from_registrar(registrar).descriptors())
}

fn collect_schedule_manifest(schedules: &[ScheduleRegistrar]) -> Result<Vec<ScheduleDescriptor>> {
    Ok(crate::scheduler::build_registry(schedules)?.descriptors())
}

/// CLI registrar for the `types:export` command.
pub fn builtin_cli_registrar(routes: Vec<RouteRegistrar>) -> CommandRegistrar {
    builtin_cli_registrar_with_websocket_routes(routes, Vec::new())
}

/// CLI registrar for the `types:export` command, including WebSocket channel metadata.
pub fn builtin_cli_registrar_with_websocket_routes(
    routes: Vec<RouteRegistrar>,
    websocket_routes: Vec<WebSocketRouteRegistrar>,
) -> CommandRegistrar {
    builtin_cli_registrar_with_websocket_routes_and_schedules(routes, websocket_routes, Vec::new())
}

/// CLI registrar for the `types:export` command, including WebSocket channel and schedule metadata.
pub fn builtin_cli_registrar_with_websocket_routes_and_schedules(
    routes: Vec<RouteRegistrar>,
    websocket_routes: Vec<WebSocketRouteRegistrar>,
    schedules: Vec<ScheduleRegistrar>,
) -> CommandRegistrar {
    Arc::new(move |registry| {
        let routes = routes.clone();
        let websocket_routes = websocket_routes.clone();
        let schedules = schedules.clone();
        registry.command(
            TYPES_EXPORT_COMMAND,
            clap::Command::new("types:export")
                .about("Export registered TypeScript types")
                .arg(
                    clap::Arg::new("output")
                        .long("output")
                        .short('o')
                        .help("Output directory (overrides config)"),
                ),
            move |invocation| {
                let routes = routes.clone();
                let websocket_routes = websocket_routes.clone();
                let schedules = schedules.clone();
                async move {
                    let output = if let Some(dir) = invocation.matches().get_one::<String>("output")
                    {
                        PathBuf::from(dir)
                    } else {
                        let config = invocation.app().config().typescript().unwrap_or_default();
                        PathBuf::from(config.output_dir)
                    };

                    let route_manifest = collect_route_manifest(&routes)?;
                    let websocket_channel_manifest =
                        collect_websocket_channel_manifest(&websocket_routes)?;
                    let schedule_manifest = collect_schedule_manifest(&schedules)?;
                    let scheduler_config = invocation.app().config().scheduler()?;
                    let scheduler_runtime_manifest =
                        SchedulerRuntimeManifestDescriptor::from_config(&scheduler_config);
                    let command_manifest = invocation.commands().to_vec();
                    let event_manifest = invocation.app().events()?.descriptors();
                    let job_manifest = invocation.app().job_runtime()?.descriptors();
                    let jobs_config = invocation.app().config().jobs()?;
                    let job_runtime_manifest =
                        JobRuntimeManifestDescriptor::from_config(&jobs_config);
                    let validation_rule_manifest = invocation.app().rules().descriptors();
                    let plugin_manifest = invocation.app().plugins()?.descriptors();
                    let storage_config = invocation.app().config().storage()?;
                    let storage_runtime_manifest =
                        StorageRuntimeManifestDescriptor::from_config(&storage_config);
                    let storage_manifest = invocation.app().storage()?.descriptors();
                    let email_config = invocation.app().config().email()?;
                    let email_runtime_manifest =
                        EmailRuntimeManifestDescriptor::from_config(&email_config);
                    let email_manifest = invocation.app().email()?.descriptors();
                    let readiness_manifest =
                        invocation.app().diagnostics()?.readiness_descriptors();
                    let app_config = invocation.app().config().app()?;
                    let app_manifest = AppManifestDescriptor::from_config(&app_config);
                    let auth_config = invocation.app().config().auth()?;
                    let auth_runtime_manifest = AuthRuntimeManifestDescriptor::from_config_with_app(
                        &auth_config,
                        &app_config,
                    );
                    let audit_config = invocation.app().config().audit()?;
                    let audit_manifest = AuditManifestDescriptor::from_config(&audit_config);
                    let logging_config = invocation.app().config().logging()?;
                    let logging_manifest = LoggingManifestDescriptor::from_config(&logging_config);
                    let http_config = invocation.app().config().http()?;
                    let http_manifest = HttpManifestDescriptor::from_config(&http_config);
                    let websocket_config = invocation.app().config().websocket()?;
                    let websocket_runtime_manifest =
                        WebSocketRuntimeManifestDescriptor::from_config(&websocket_config);
                    let redis = invocation.app().redis()?;
                    let cache_config = invocation.app().config().cache()?;
                    let cache_manifest = CacheManifestDescriptor::from_config(
                        &cache_config,
                        redis.is_configured(),
                        redis.is_configured().then(|| redis.namespace().to_string()),
                    );
                    let database_config = invocation.app().config().database()?;
                    let database_manifest =
                        DatabaseManifestDescriptor::from_config(&database_config);
                    let observability_config = invocation.app().config().observability()?;
                    let observability_manifest =
                        ObservabilityManifestDescriptor::from_config(&observability_config);
                    let i18n_manifest = invocation
                        .app()
                        .i18n()
                        .map(|manager| manager.descriptor())
                        .unwrap_or_else(|_| {
                            invocation
                                .app()
                                .config()
                                .i18n()
                                .map(|config| I18nManifestDescriptor::from_config(&config))
                                .unwrap_or_default()
                        });
                    let datatable_config = invocation.app().config().datatable()?;
                    let datatable_runtime_manifest =
                        DatatableRuntimeManifestDescriptor::from_config(&datatable_config);
                    let datatable_manifest = invocation.app().datatables()?.descriptors()?;
                    let auth_guard_manifest = invocation.app().auth()?.descriptors();
                    let auth_policy_manifest = invocation.app().authorizer()?.descriptors();
                    let authenticatable_manifest =
                        invocation.app().authenticatables()?.descriptors();
                    let app_timezone = app_config.timezone.as_str();
                    export_all_with_manifest_context(
                        &output,
                        ExportAllManifestContext {
                            app: &app_manifest,
                            auth_guards: &auth_guard_manifest,
                            auth_policies: &auth_policy_manifest,
                            authenticatables: &authenticatable_manifest,
                            auth_runtime: &auth_runtime_manifest,
                            audit: &audit_manifest,
                            logging: &logging_manifest,
                            routes: &route_manifest,
                            http: &http_manifest,
                            websocket_channels: &websocket_channel_manifest,
                            websocket_runtime: &websocket_runtime_manifest,
                            events: &event_manifest,
                            jobs: &job_manifest,
                            job_runtime: &job_runtime_manifest,
                            commands: &command_manifest,
                            schedules: &schedule_manifest,
                            scheduler_runtime: &scheduler_runtime_manifest,
                            validation_rules: &validation_rule_manifest,
                            validation_rule_manifest_authoritative: true,
                            plugins: &plugin_manifest,
                            storage_disks: &storage_manifest,
                            storage_runtime: &storage_runtime_manifest,
                            email_mailers: &email_manifest,
                            email_runtime: &email_runtime_manifest,
                            i18n: &i18n_manifest,
                            readiness_probes: &readiness_manifest,
                            cache: &cache_manifest,
                            database: &database_manifest,
                            observability: &observability_manifest,
                            datatables: &datatable_manifest,
                            datatable_runtime: &datatable_runtime_manifest,
                            app_timezone: &app_timezone,
                        },
                    )
                }
            },
        )?;
        Ok(())
    })
}

