    fn route_manifest_entry(id: &'static str, path: &str, params: &[&str]) -> RouteManifestEntry {
        RouteManifestEntry {
            id: RouteId::new(id),
            path: path.to_string(),
            method: Some("get".to_string()),
            params: params.iter().map(|param| (*param).to_string()).collect(),
            client_export: true,
            request_transport: Some(RouteRequestTransport::Query),
            request_media_type: None,
            requires_auth: true,
            allows_mfa_pending_token: true,
            has_authorize_callback: true,
            guard: Some(GuardId::new("admin")),
            permissions: vec![PermissionId::new("users.read")],
            middleware_group: Some("api".to_string()),
            audit_area: Some("admin".to_string()),
            rate_limits: vec![RouteManifestRateLimit {
                max_requests: 60,
                window_seconds: 60,
                by: RateLimitBy::Actor,
            }],
            operation_id: Some(id.to_string()),
            summary: Some("Show user".to_string()),
            description: Some("Show a single admin user.".to_string()),
            tags: vec!["admin".to_string(), "users".to_string()],
            deprecated: true,
            request: Some("ShowUserRequest".to_string()),
            responses: vec![route_manifest_response(200, "ShowUserResponse")],
        }
    }

    fn route_manifest_response(status: u16, schema: &str) -> RouteManifestResponse {
        RouteManifestResponse {
            status,
            schema: schema.to_string(),
            has_body: route_response_has_body(status, schema),
            media_type: route_response_media_type(status, schema),
        }
    }

    fn generated_function_source<'a>(source: &'a str, start: &str, end: &str) -> &'a str {
        source
            .split_once(start)
            .unwrap_or_else(|| panic!("generated runtime should contain `{start}`"))
            .1
            .split_once(end)
            .unwrap_or_else(|| panic!("generated runtime should contain `{end}` after `{start}`"))
            .0
    }

    fn generated_switch_cases(source: &str) -> BTreeSet<String> {
        source
            .lines()
            .filter_map(|line| {
                line.trim_start()
                    .strip_prefix("case \"")
                    .and_then(|rest| rest.split_once('"'))
                    .map(|(code, _)| code.to_string())
            })
            .collect()
    }

    fn assert_generated_switch_cases(function_name: &str, source: &str, expected_codes: &[&str]) {
        let actual = generated_switch_cases(source);
        let expected = expected_codes
            .iter()
            .map(|code| (*code).to_string())
            .collect::<BTreeSet<_>>();
        assert_eq!(
            expected.len(),
            expected_codes.len(),
            "expected validation rule code list for `{function_name}` contains duplicates"
        );

        let missing = expected.difference(&actual).cloned().collect::<Vec<_>>();
        let unexpected = actual.difference(&expected).cloned().collect::<Vec<_>>();
        assert!(
            missing.is_empty() && unexpected.is_empty(),
            "generated `{function_name}` validation cases drifted; missing: {missing:?}; unexpected: {unexpected:?}"
        );
    }

