    #[test]
    fn ts_type_planning_allows_duplicate_registration_for_same_file() {
        let entries = [
            ts_type_entry("SharedContract", shared_ts_output_path),
            ts_type_entry("SharedContract", shared_ts_output_path),
        ];
        let refs = entries.iter().collect::<Vec<_>>();

        let files = planned_ts_type_files(&refs)
            .expect("duplicate identical TypeScript registration should stay idempotent");

        assert_eq!(
            files.get("SharedContract").map(String::as_str),
            Some("shared/Contract.ts")
        );
    }

    #[test]
    fn ts_type_planning_rejects_one_type_with_multiple_files() {
        let entries = [
            ts_type_entry("SharedContract", first_ts_output_path),
            ts_type_entry("SharedContract", second_ts_output_path),
        ];
        let refs = entries.iter().collect::<Vec<_>>();

        let error = planned_ts_type_files(&refs)
            .expect_err("one TypeScript export name with multiple files should fail");

        assert!(
            error.to_string().contains(
                "TypeScript export `SharedContract` registered multiple output paths: `First.ts` and `Second.ts`"
            ),
            "unexpected error: {error}"
        );
    }

    #[test]
    fn ts_type_planning_rejects_multiple_types_with_one_file() {
        let entries = [
            ts_type_entry("FirstContract", shared_ts_output_path),
            ts_type_entry("SecondContract", shared_ts_output_path),
        ];
        let refs = entries.iter().collect::<Vec<_>>();

        let error = planned_ts_type_files(&refs)
            .expect_err("multiple TypeScript export names sharing one file should fail");

        assert!(
            error.to_string().contains(
                "TypeScript exports `FirstContract` and `SecondContract` both target output path `shared/Contract.ts`"
            ),
            "unexpected error: {error}"
        );
    }

    #[test]
    fn ts_type_planning_rejects_invalid_type_names() {
        let entries = [ts_type_entry("../SharedContract", shared_ts_output_path)];
        let refs = entries.iter().collect::<Vec<_>>();

        let error = planned_ts_type_files(&refs)
            .expect_err("invalid manual TypeScript export names should fail");

        assert!(
            error.to_string().contains(
                "TypeScript type export contains invalid type name `../SharedContract`; names must be non-empty, trimmed TypeScript identifiers"
            ),
            "unexpected error: {error}"
        );
    }

    #[test]
    fn exported_type_names_reject_type_app_enum_collisions() {
        let mut type_files = BTreeMap::new();
        type_files.insert("ManualStatus", "custom/ManualStatusDto.ts".to_string());
        let mut app_enums = BTreeMap::new();
        app_enums.insert("ManualStatus", valid_manual_app_enum_meta());
        let route_helpers = Vec::new();

        let error = ensure_unique_barrel_export_names(&type_files, &app_enums, &route_helpers)
            .expect_err("type and AppEnum exports with the same name should fail");

        assert!(
            error.to_string().contains(
                "TypeScript type export `ManualStatus` and AppEnum export `ManualStatus` both export TypeScript name `ManualStatus`"
            ),
            "unexpected error: {error}"
        );
    }

