    #[test]
    fn exported_type_names_reject_route_helper_framework_collisions() {
        let type_files = BTreeMap::new();
        let app_enums = BTreeMap::new();
        let routes = [route_manifest_entry(
            "route_manifest",
            "/api/v1/route-manifest",
            &[],
        )];
        let route_helpers = planned_route_helpers(&routes).expect("route helper should be planned");

        let error = ensure_unique_barrel_export_names(&type_files, &app_enums, &route_helpers)
            .expect_err("route helpers should not reuse framework barrel names");

        assert!(
            error.to_string().contains(
                "Foundry route manifest export and route endpoint helper `route_manifest` both export TypeScript name `RouteManifest`"
            ),
            "unexpected error: {error}"
        );
    }

