    #[test]
    fn framework_typescript_modules_describe_output_files_and_barrel_exports() {
        let modules = super::FRAMEWORK_TYPESCRIPT_MODULES;
        let files = modules.iter().map(|module| module.file).collect::<Vec<_>>();
        let module_names = modules
            .iter()
            .map(|module| module.module)
            .collect::<Vec<_>>();
        let owners = modules
            .iter()
            .map(|module| module.owner)
            .collect::<Vec<_>>();

        assert_eq!(
            files,
            vec![
                "AppManifest.ts",
                "AuthManifest.ts",
                "AuditManifest.ts",
                "LoggingManifest.ts",
                "RouteManifest.ts",
                "HttpManifest.ts",
                "WebSocketChannelManifest.ts",
                "EventManifest.ts",
                "JobManifest.ts",
                "CommandManifest.ts",
                "ScheduleManifest.ts",
                "ValidationRuleManifest.ts",
                "PluginManifest.ts",
                "StorageManifest.ts",
                "EmailManifest.ts",
                "I18nManifest.ts",
                "ReadinessManifest.ts",
                "SettingManifest.ts",
                "CacheManifest.ts",
                "DatabaseManifest.ts",
                "ObservabilityManifest.ts",
                "DatatableManifest.ts",
                "NotificationManifest.ts",
                "FoundryEndpoint.ts",
            ]
        );
        assert_eq!(
            module_names,
            vec![
                "AppManifest",
                "AuthManifest",
                "AuditManifest",
                "LoggingManifest",
                "RouteManifest",
                "HttpManifest",
                "WebSocketChannelManifest",
                "EventManifest",
                "JobManifest",
                "CommandManifest",
                "ScheduleManifest",
                "ValidationRuleManifest",
                "PluginManifest",
                "StorageManifest",
                "EmailManifest",
                "I18nManifest",
                "ReadinessManifest",
                "SettingManifest",
                "CacheManifest",
                "DatabaseManifest",
                "ObservabilityManifest",
                "DatatableManifest",
                "NotificationManifest",
                "FoundryEndpoint",
            ]
        );
        assert_eq!(
            owners,
            vec![
                "Foundry app manifest",
                "Foundry auth manifest",
                "Foundry audit manifest",
                "Foundry logging manifest",
                "Foundry route manifest",
                "Foundry HTTP manifest",
                "Foundry WebSocket channel manifest",
                "Foundry event manifest",
                "Foundry job manifest",
                "Foundry command manifest",
                "Foundry schedule manifest",
                "Foundry validation rule manifest",
                "Foundry plugin manifest",
                "Foundry storage manifest",
                "Foundry email manifest",
                "Foundry i18n manifest",
                "Foundry readiness manifest",
                "Foundry setting manifest",
                "Foundry cache manifest",
                "Foundry database manifest",
                "Foundry observability manifest",
                "Foundry datatable manifest",
                "Foundry notification manifest",
                "Foundry endpoint runtime",
            ]
        );

        let mut seen_files = BTreeSet::new();
        let mut seen_exports = BTreeSet::new();
        for module in modules {
            assert!(
                seen_files.insert(module.file),
                "duplicate framework TypeScript output file `{}`",
                module.file
            );
            for export in module.exports {
                assert!(
                    seen_exports.insert(export.name),
                    "duplicate framework TypeScript barrel export `{}`",
                    export.name
                );
            }
        }
    }

