    #[test]
    fn export_preserves_unmanaged_typescript_files() {
        let dir = tempdir().unwrap();
        fs::write(
            dir.path().join("manual.ts"),
            "export const manual = true;\n",
        )
        .unwrap();

        export_all(dir.path()).unwrap();

        assert_eq!(
            fs::read_to_string(dir.path().join("manual.ts")).unwrap(),
            "export const manual = true;\n"
        );
        assert!(dir.path().join(TYPES_EXPORT_MANIFEST).exists());
    }

    #[test]
    fn export_removes_stale_files_from_previous_manifest() {
        let dir = tempdir().unwrap();
        fs::write(dir.path().join("StaleGenerated.ts"), "stale\n").unwrap();
        fs::write(
            dir.path().join(TYPES_EXPORT_MANIFEST),
            serde_json::to_string(&vec!["StaleGenerated.ts"]).unwrap(),
        )
        .unwrap();

        export_all(dir.path()).unwrap();

        assert!(!dir.path().join("StaleGenerated.ts").exists());
        let manifest: Vec<String> = serde_json::from_str(
            &fs::read_to_string(dir.path().join(TYPES_EXPORT_MANIFEST)).unwrap(),
        )
        .unwrap();
        assert!(manifest.iter().any(|file| file == "index.ts"));
        assert!(manifest.iter().any(|file| file == "AppManifest.ts"));
        assert!(manifest.iter().any(|file| file == "AuthManifest.ts"));
        assert!(manifest.iter().any(|file| file == "AuditManifest.ts"));
        assert!(manifest.iter().any(|file| file == "LoggingManifest.ts"));
        assert!(manifest.iter().any(|file| file == "RouteManifest.ts"));
        assert!(manifest.iter().any(|file| file == "HttpManifest.ts"));
        assert!(manifest
            .iter()
            .any(|file| file == "WebSocketChannelManifest.ts"));
        assert!(manifest.iter().any(|file| file == "EventManifest.ts"));
        assert!(manifest.iter().any(|file| file == "JobManifest.ts"));
        assert!(manifest.iter().any(|file| file == "CommandManifest.ts"));
        assert!(manifest.iter().any(|file| file == "ScheduleManifest.ts"));
        assert!(manifest
            .iter()
            .any(|file| file == "ValidationRuleManifest.ts"));
        assert!(manifest.iter().any(|file| file == "PluginManifest.ts"));
        assert!(manifest.iter().any(|file| file == "StorageManifest.ts"));
        assert!(manifest.iter().any(|file| file == "EmailManifest.ts"));
        assert!(manifest.iter().any(|file| file == "I18nManifest.ts"));
        assert!(manifest.iter().any(|file| file == "ReadinessManifest.ts"));
        assert!(manifest.iter().any(|file| file == "SettingManifest.ts"));
        assert!(manifest.iter().any(|file| file == "CacheManifest.ts"));
        assert!(manifest
            .iter()
            .any(|file| file == "ObservabilityManifest.ts"));
        assert!(manifest.iter().any(|file| file == "DatatableManifest.ts"));
        assert!(manifest
            .iter()
            .any(|file| file == "NotificationManifest.ts"));
        assert!(manifest.iter().any(|file| file == "FoundryEndpoint.ts"));
    }

    #[cfg(unix)]
    #[test]
    fn export_replaces_symlinked_planned_file_without_touching_target() {
        use std::os::unix::fs::symlink;

        let dir = tempdir().unwrap();
        let outside = dir.path().join("outside.ts");
        fs::write(&outside, "export const outside = true;\n").unwrap();
        symlink(&outside, dir.path().join("index.ts")).unwrap();

        export_all(dir.path()).unwrap();

        assert_eq!(
            fs::read_to_string(&outside).unwrap(),
            "export const outside = true;\n"
        );
        assert!(!fs::symlink_metadata(dir.path().join("index.ts"))
            .unwrap()
            .file_type()
            .is_symlink());
    }

