    #[test]
    fn websocket_channel_manifest_exports_typed_payload_map() {
        let mut channel = websocket_channel_descriptor("chat.rooms");
        channel.client_events = vec![ChannelEventId::new("typing")];
        channel.server_events = vec![ChannelEventId::new("message")];
        let payloads = [
            super::TsWebSocketPayload::server(
                ChannelId::new("chat.rooms"),
                ChannelEventId::new("message"),
                "MinimalNotificationPayload",
            ),
            super::TsWebSocketPayload::client_event(
                ChannelId::new("chat.rooms"),
                ChannelEventId::new("typing"),
                "Array<MinimalNotificationPayload>",
            ),
        ];
        let metadata = collect_websocket_payload_metadata(payloads.iter()).unwrap();
        let mut exported_types = BTreeMap::new();
        exported_types.insert(
            "MinimalNotificationPayload".to_string(),
            "MinimalNotificationPayload.ts".to_string(),
        );

        let runtime = super::WebSocketRuntimeManifestDescriptor::default();
        let manifest = render_websocket_channel_manifest_with_payloads(
            &[channel],
            &runtime,
            &metadata,
            &exported_types,
        )
        .unwrap();

        assert!(
            manifest.contains(
                "import type { MinimalNotificationPayload } from \"./MinimalNotificationPayload\";"
            ),
            "expected websocket payload manifest to import registered payload DTOs:\n{manifest}"
        );
        assert!(
            manifest.contains("\"server:chat.rooms:message\": { direction: \"server\", channel: \"chat.rooms\", event: \"message\", payload: \"MinimalNotificationPayload\" }")
                && manifest.contains("\"client:chat.rooms:typing\": { direction: \"client\", channel: \"chat.rooms\", event: \"typing\", payload: \"Array<MinimalNotificationPayload>\" }"),
            "expected websocket payload manifest entries:\n{manifest}"
        );
        assert!(
            manifest.contains("export type WebSocketServerPayloadMap = {")
                && manifest.contains("readonly \"chat.rooms\": {")
                && manifest.contains("readonly \"message\": MinimalNotificationPayload;")
                && manifest.contains("export type WebSocketClientEventPayloadMap = {")
                && manifest.contains("readonly \"typing\": MinimalNotificationPayload[];")
                && manifest.contains("export type TypedWebSocketAppServerFrame")
                && manifest.contains("export type TypedWebSocketClientEventFrame")
                && manifest.contains("export function typedClientEventToChannel")
                && manifest.contains("hasWebSocketServerPayload")
                && manifest.contains("hasWebSocketClientEventPayload"),
            "expected websocket payload maps and typed helpers:\n{manifest}"
        );
    }

