    #[test]
    fn auth_manifest_exports_effective_runtime_config_values() {
        let config = AuthConfig {
            bearer_prefix: " Token ".to_string(),
            sessions: SessionConfig {
                cookie_same_site: " Strict ".to_string(),
                ..Default::default()
            },
            lockout: LockoutConfig {
                max_failures: 0,
                lockout_minutes: 0,
                window_minutes: 0,
                ..Default::default()
            },
            mfa: MfaConfig {
                issuer: " ".to_string(),
                pending_token_ttl_minutes: 0,
                recovery_codes: 0,
                ..Default::default()
            },
            ..Default::default()
        };
        let app = AppConfig {
            name: "Acme Admin".to_string(),
            ..Default::default()
        };
        let runtime = super::AuthRuntimeManifestDescriptor::from_config_with_app(&config, &app);

        let manifest = render_auth_manifest(&[], &[], &[], &runtime).unwrap();

        assert!(
            manifest.contains("bearerPrefix: \"Token\"")
                && manifest.contains("cookieSameSite: \"strict\"")
                && manifest.contains("maxFailures: 1")
                && manifest.contains("lockoutMinutes: 1")
                && manifest.contains("windowMinutes: 1")
                && manifest.contains("issuer: \"Acme Admin\"")
                && manifest.contains("pendingTokenTtlMinutes: 1")
                && manifest.contains("recoveryCodes: 1"),
            "expected auth runtime manifest to export effective backend config values:\n{manifest}"
        );
    }

    #[test]
    fn auth_manifest_rejects_runtime_number_above_typescript_safe_integer_limit() {
        let mut runtime = super::AuthRuntimeManifestDescriptor::default();
        runtime.access_token_ttl_minutes = super::TYPESCRIPT_MAX_SAFE_INTEGER as u64 + 1;

        let error = render_auth_manifest(&[], &[], &[], &runtime).unwrap_err();

        assert!(
            error
                .to_string()
                .contains("AuthManifest TypeScript export access token TTL minutes")
                && error
                    .to_string()
                    .contains("above TypeScript's safe integer limit"),
            "unexpected auth manifest error: {error}"
        );
    }

    #[test]
    fn auth_manifest_rejects_zero_direct_runtime_ttl_values() {
        let mut runtime = super::AuthRuntimeManifestDescriptor::default();
        runtime.session_ttl_minutes = 0;

        let error = render_auth_manifest(&[], &[], &[], &runtime).unwrap_err();

        assert!(
            error.to_string().contains(
                "AuthManifest TypeScript export contains invalid session TTL minutes `0`"
            ),
            "unexpected auth manifest error: {error}"
        );
    }

    #[test]
    fn auth_manifest_rejects_invalid_runtime_bearer_prefix() {
        let mut runtime = super::AuthRuntimeManifestDescriptor::default();
        runtime.bearer_prefix = "Bearer Token".to_string();

        let error = render_auth_manifest(&[], &[], &[], &runtime).unwrap_err();

        assert!(
            error
                .to_string()
                .contains("bearer prefixes cannot contain whitespace or control characters"),
            "unexpected auth manifest error: {error}"
        );
    }

    #[test]
    fn auth_manifest_rejects_invalid_runtime_session_cookie_config() {
        let mut runtime = super::AuthRuntimeManifestDescriptor::default();
        runtime.session_cookie_same_site = "none".to_string();
        runtime.session_cookie_secure = false;

        let error = render_auth_manifest(&[], &[], &[], &runtime).unwrap_err();

        assert!(
            error
                .to_string()
                .contains("cookie SameSite=None requires Secure=true"),
            "unexpected auth manifest error: {error}"
        );
    }

    #[test]
    fn auth_manifest_rejects_duplicate_runtime_mfa_required_roles() {
        let mut runtime = super::AuthRuntimeManifestDescriptor::default();
        runtime.mfa_required_roles = BTreeMap::from([(
            "admin.web".to_string(),
            vec!["owner".to_string(), "owner".to_string()],
        )]);

        let error = render_auth_manifest(&[], &[], &[], &runtime).unwrap_err();

        assert!(
            error.to_string().contains(
                "AuthManifest TypeScript export MFA required-role guard `admin.web` contains duplicate role `owner`"
            ),
            "unexpected auth manifest error: {error}"
        );
    }

    #[test]
    fn auth_manifest_rejects_unregistered_authenticatable_guards() {
        let guards = [auth_guard_descriptor("api", AuthGuardKind::Bearer, true)];
        let authenticatables = [authenticatable_descriptor("admin")];
        let runtime = super::AuthRuntimeManifestDescriptor::default();

        let error = render_auth_manifest(&guards, &[], &authenticatables, &runtime).unwrap_err();

        assert!(
            error.to_string().contains(
                "AuthManifest TypeScript export authenticatable guard `admin` does not match a registered auth guard"
            ),
            "unexpected error: {error}"
        );
    }

