    #[test]
    fn plugin_manifest_rejects_duplicate_plugin_ids() {
        let plugins = [
            plugin_descriptor("foundry.example"),
            plugin_descriptor("foundry.example"),
        ];

        let error = render_plugin_manifest(&plugins).unwrap_err();

        assert!(
            error.to_string().contains(
                "PluginManifest TypeScript export contains duplicate plugin id `foundry.example`"
            ),
            "unexpected error: {error}"
        );
    }

    #[test]
    fn plugin_manifest_rejects_contribution_count_above_typescript_safe_integer_limit() {
        if usize::MAX as u128 <= super::TYPESCRIPT_MAX_SAFE_INTEGER {
            return;
        }
        let mut plugin = plugin_descriptor("foundry.example");
        plugin.contributions.route_count = (super::TYPESCRIPT_MAX_SAFE_INTEGER + 1) as usize;

        let error = render_plugin_manifest(&[plugin])
            .expect_err("unsafe plugin contribution counts should fail");

        assert!(
            error.to_string().contains(
                "PluginManifest TypeScript export plugin `foundry.example` contribution `routes` count"
            ),
            "unexpected error: {error}"
        );
    }

    #[test]
    fn plugin_manifest_rejects_total_contribution_count_above_typescript_safe_integer_limit() {
        if usize::MAX as u128 <= super::TYPESCRIPT_MAX_SAFE_INTEGER {
            return;
        }
        let mut plugin = plugin_descriptor("foundry.example");
        plugin.contributions.route_count = super::TYPESCRIPT_MAX_SAFE_INTEGER as usize;

        let error = render_plugin_manifest(&[plugin])
            .expect_err("unsafe aggregate plugin contribution counts should fail");

        assert!(
            error
                .to_string()
                .contains("PluginManifest TypeScript export total contribution count"),
            "unexpected error: {error}"
        );
    }

    #[test]
    fn plugin_manifest_rejects_selected_contribution_total_above_typescript_safe_integer_limit() {
        if usize::MAX as u128 <= super::TYPESCRIPT_MAX_SAFE_INTEGER {
            return;
        }
        let unsafe_half = (super::TYPESCRIPT_MAX_SAFE_INTEGER / 2 + 1) as usize;
        let mut first = plugin_descriptor("foundry.example");
        first.contributions.route_count = unsafe_half;
        let mut second = plugin_descriptor("foundry.extra");
        second.contributions.route_count = unsafe_half;

        let error = render_plugin_manifest(&[first, second])
            .expect_err("unsafe selected plugin contribution totals should fail");

        assert!(
            error
                .to_string()
                .contains("PluginManifest TypeScript export contribution `routes` total"),
            "unexpected error: {error}"
        );
    }

    #[test]
    fn plugin_manifest_rejects_asset_contribution_count_mismatch() {
        let mut plugin = plugin_descriptor("foundry.example");
        plugin.contributions.asset_count = 0;

        let error = render_plugin_manifest(&[plugin])
            .expect_err("plugin asset contribution count drift should fail");

        assert!(
            error.to_string().contains(
                "PluginManifest TypeScript export plugin `foundry.example` contribution `assets` count `0` does not match assets length `1`"
            ),
            "unexpected error: {error}"
        );
    }

    #[test]
    fn plugin_manifest_rejects_scaffold_contribution_count_mismatch() {
        let mut plugin = plugin_descriptor("foundry.example");
        plugin.contributions.scaffold_count = 0;

        let error = render_plugin_manifest(&[plugin])
            .expect_err("plugin scaffold contribution count drift should fail");

        assert!(
            error.to_string().contains(
                "PluginManifest TypeScript export plugin `foundry.example` contribution `scaffolds` count `0` does not match scaffolds length `1`"
            ),
            "unexpected error: {error}"
        );
    }

