    #[test]
    fn i18n_manifest_rejects_duplicate_locales() {
        let i18n =
            i18n_manifest_descriptor("en", "en", &[("en", true, true), ("en", false, false)]);

        let error = render_i18n_manifest(&i18n).unwrap_err();

        assert!(
            error
                .to_string()
                .contains("I18nManifest TypeScript export contains duplicate locale `en`"),
            "unexpected error: {error}"
        );
    }

