    #[test]
    fn app_manifest_exports_safe_app_config_without_signing_key() {
        let descriptor = super::AppManifestDescriptor::from_config(&AppConfig {
            name: "Tenant Portal".to_string(),
            environment: Environment::Custom("eu-prod".to_string()),
            timezone: crate::Timezone::parse("Asia/Kuala_Lumpur").unwrap(),
            signing_key: "do-not-export".to_string(),
            background_shutdown_timeout_ms: 12_345,
        });

        let manifest = super::render_app_manifest(&descriptor).unwrap();

        assert!(
            manifest.contains("name: \"Tenant Portal\"")
                && manifest.contains("environment: \"eu-prod\"")
                && manifest.contains("environmentKind: \"custom\"")
                && manifest.contains("production: false")
                && manifest.contains("productionLike: false")
                && manifest.contains("timezone: \"Asia/Kuala_Lumpur\"")
                && manifest.contains("backgroundShutdownTimeoutMs: 12345")
                && manifest.contains("function freezeAppManifestValue<TValue>(value: TValue): TValue")
                && manifest.contains("const seen = new WeakSet<object>();")
                && manifest.contains("return Object.freeze(item);")
                && manifest.contains(
                    "export const ApplicationEnvironmentKinds = freezeAppManifestValue([\"development\", \"production\", \"staging\", \"testing\", \"custom\"] as const);"
                )
                && manifest.contains("export const AppManifest = freezeAppManifestValue({")
                && manifest.contains(
                    "export type AppEnvironmentKind = (typeof ApplicationEnvironmentKinds)[number];"
                )
                && manifest.contains("export const ApplicationName")
                && manifest.contains("export const ApplicationEnvironment")
                && manifest.contains("export const ApplicationEnvironmentKind")
                && manifest.contains("export const ApplicationTimezone")
                && manifest.contains("export const ApplicationBackgroundShutdownTimeoutMs")
                && manifest.contains("export function isAppEnvironmentKind")
                && manifest.contains(
                    "export function appEnvironmentKindOrNull(value: string): AppEnvironmentKind | null"
                )
                && manifest.contains("return isAppEnvironmentKind(value) ? value : null;")
                && manifest.contains("export function appEnvironmentKinds(): AppEnvironmentKind[]")
                && manifest.contains("export function appEnvironmentKindCount(): number")
                && manifest.contains("export function appHasEnvironmentKinds(): boolean")
                && manifest.contains(
                    "export function appFirstEnvironmentKind(): AppEnvironmentKind | undefined"
                )
                && manifest.contains(
                    "export function appFirstEnvironmentKindOrNull(): AppEnvironmentKind | null"
                )
                && manifest.contains("return appFirstEnvironmentKind() ?? null;")
                && manifest.contains("export function appName")
                && manifest.contains("export function appEnvironment")
                && manifest.contains("export function appEnvironmentIs")
                && manifest.contains("export function appEnvironmentKind")
                && manifest.contains("export function appEnvironmentKindIs")
                && manifest.contains("export function appTimezone")
                && manifest.contains("export function appBackgroundShutdownTimeoutMs")
                && manifest.contains("export function appBackgroundShutdownImmediate")
                && manifest.contains("export function appIsCustom")
                && manifest.contains("return appEnvironmentKindIs(\"custom\");")
                && manifest.contains("export function appIsProductionLike")
                && !manifest.contains("do-not-export")
                && !manifest.contains("signing"),
            "expected app manifest metadata without signing key leakage:\n{manifest}"
        );
    }

