    #[test]
    fn job_manifest_exports_runtime_config_without_worker_internals() {
        let mut queue_priorities = HashMap::new();
        queue_priorities.insert("critical".to_string(), 10);
        queue_priorities.insert("emails".to_string(), 2);
        let runtime = super::JobRuntimeManifestDescriptor::from_config(&JobsConfig {
            queue: crate::support::QueueId::new("critical"),
            max_retries: 7,
            poll_interval_ms: 25,
            lease_ttl_ms: 45_000,
            requeue_batch_size: 128,
            max_concurrent_jobs: 4,
            timeout_seconds: 120,
            shutdown_timeout_ms: 5_000,
            track_history: false,
            history_retention_days: 14,
            history_prune_interval_ms: 1_800_000,
            history_prune_batch_size: 500,
            queue_priorities,
        });

        let jobs = [
            job_descriptor("reports.daily", "critical"),
            job_descriptor("mail.welcome", "emails"),
        ];
        let manifest = render_job_manifest(&jobs, &runtime, &BTreeMap::new(), &BTreeMap::new())
            .expect("job runtime config should render");

        assert!(
            manifest.contains("export const JobRuntimeManifest = freezeJobManifestValue({")
                && manifest.contains(
                    "\"reports.daily\": { id: \"reports.daily\", queue: \"critical\", queuePriority: 10, payload: null }"
                )
                && manifest.contains(
                    "\"mail.welcome\": { id: \"mail.welcome\", queue: \"emails\", queuePriority: 2, payload: null }"
                )
                && manifest.contains("defaultQueue: \"critical\"")
                && manifest.contains("maxRetries: 7")
                && manifest.contains("maxConcurrentJobs: 4")
                && manifest.contains("timeoutSeconds: 120")
                && manifest.contains("\"critical\": 10")
                && manifest.contains("\"emails\": 2")
                && manifest.contains("history: { enabled: false, retentionDays: 14 }")
                && manifest
                    .contains("export const JobDefaultQueue = JobRuntimeManifest.defaultQueue;")
                && manifest.contains("export const JobMaxRetries = JobRuntimeManifest.maxRetries;")
                && manifest.contains(
                    "export function jobDefaultQueueName(): typeof JobRuntimeManifest.defaultQueue"
                )
                && manifest.contains(
                    "export function jobMaxRetries(): typeof JobRuntimeManifest.maxRetries"
                )
                && manifest.contains(
                    "export function jobMaxConcurrentJobs(): typeof JobRuntimeManifest.maxConcurrentJobs"
                )
                && manifest.contains(
                    "export function jobTimeoutSeconds(): typeof JobRuntimeManifest.timeoutSeconds"
                )
                && manifest.contains(
                    "export function jobHistoryRetentionDays(): typeof JobRuntimeManifest.history.retentionDays"
                )
                && manifest.contains("export function jobPriority")
                && manifest.contains("export function jobPriorityQueueNames(): string[]")
                && manifest.contains(
                    "return Object.keys(JobRuntimeManifest.queuePriorities);"
                )
                && manifest.contains("export function jobPriorityQueueNameCount(): number")
                && manifest.contains("export function jobHasPriorityQueueNames(): boolean")
                && manifest.contains(
                    "export function jobFirstPriorityQueueName(): string | undefined"
                )
                && manifest
                    .contains("export function jobQueuePriority(queue: string): number | null")
                && manifest.contains("export function jobHistoryTracked(): boolean"),
            "expected job runtime manifest and helpers:\n{manifest}"
        );
        assert!(
            !manifest.contains("pollInterval")
                && !manifest.contains("leaseTtl")
                && !manifest.contains("requeueBatch")
                && !manifest.contains("shutdownTimeout")
                && !manifest.contains("historyPrune"),
            "expected worker-only job timing/prune internals to stay out of the frontend manifest:\n{manifest}"
        );
    }

