    #[test]
    fn exports_validation_metadata_with_serde_wire_field_names() {
        let dir = tempdir().unwrap();
        export_all_with_routes(dir.path(), &[renamed_validation_route_manifest_entry()]).unwrap();

        let helper = fs::read_to_string(dir.path().join("routes/AuditsRenamedStore.ts")).unwrap();
        let request = fs::read_to_string(dir.path().join("RenamedValidationRequest.ts")).unwrap();

        assert!(
            request.contains("auditNote") && request.contains("newPasswordConfirmation"),
            "expected request DTO to use serde wire field names:\n{request}"
        );
        assert!(
            helper.contains(
                "{ name: \"auditNote\", rules: [{ code: \"required_if\", params: { \"other\": \"enabled\", \"value\": \"true\" } }, { code: \"required_with_all\", params: { \"other\": \"reviewer, secondReviewer\" }, values: [\"reviewer\", \"secondReviewer\"] }] }"
            ),
            "expected conditional validation metadata to use serde wire field names:\n{helper}"
        );
        assert!(
            helper.contains(
                "{ name: \"newPassword\", rules: [{ code: \"confirmed\", params: { \"other\": \"newPasswordConfirmation\" } }] }"
            ),
            "expected default confirmed metadata to use serde wire confirmation field:\n{helper}"
        );
        assert!(
            helper.contains(
                "{ field: \"auditNote\", rule: \"required_if\", message: \"Audit {{attribute}} required.\" }"
            ) && helper.contains("{ field: \"auditNote\", name: \"audit note\" }"),
            "expected validation messages and attributes to use serde wire field names:\n{helper}"
        );
    }

    #[test]
    fn exports_custom_validation_rule_metadata_with_rule_ids() {
        let dir = tempdir().unwrap();
        export_all_with_routes(dir.path(), &[custom_rule_route_manifest_entry()]).unwrap();

        let helper = fs::read_to_string(dir.path().join("routes/SmsSend.ts")).unwrap();
        let request = fs::read_to_string(dir.path().join("CustomRuleRequest.ts")).unwrap();

        assert!(
            request.contains("// Validation: required, rule(mobile) [server]\n")
                && request.contains("// Validation: rule(mobile) [server]\n"),
            "expected custom rule comments to expose the backend rule syntax:\n{request}"
        );
        assert!(
            helper.contains(
                "{ name: \"phone\", rules: [{ code: \"required\" }, { code: \"mobile\", params: { \"rule\": \"mobile\" }, serverOnly: true }] }"
            ),
            "expected literal custom rule metadata to use the registered rule id:\n{helper}"
        );
        assert!(
            helper.contains(
                "rules: [\n    { code: \"after\", params: { \"hook\": \"validate_sms_payload\" }, serverOnly: true }\n  ]"
            ),
            "expected schema-level after hook metadata to stay server-only:\n{helper}"
        );
        assert!(
            helper.contains(
                "{ name: \"typed_phone\", rules: [{ code: \"mobile\", params: { \"rule\": \"mobile\" }, serverOnly: true }] }"
            ),
            "expected typed custom rule metadata to use the registered rule id:\n{helper}"
        );
    }

    #[test]
    fn exports_manual_validation_schema_metadata_from_inventory() {
        let dir = tempdir().unwrap();
        export_all_with_routes(dir.path(), &[manual_validation_route_manifest_entry()]).unwrap();

        let helper =
            fs::read_to_string(dir.path().join("routes/ManualValidationStore.ts")).unwrap();
        let request = fs::read_to_string(dir.path().join("ManualValidationRequest.ts")).unwrap();

        assert!(
            request.contains("// Validation: required, min(5)\n")
                && request.contains("value: string"),
            "expected manual validation comments to annotate generated DTO fields:\n{request}"
        );
        assert!(
            request.contains("// Validation: manual_token [server]\n")
                && request.contains("token: string"),
            "expected manual server-only validation comments to annotate generated DTO fields:\n{request}"
        );
        assert!(
            request.contains("// Validation: size(2)\n")
                && (request.contains("tags: Array<string>") || request.contains("tags: string[]")),
            "expected manual collection validation comments to annotate generated DTO fields:\n{request}"
        );
        assert!(
            request.contains("// Validation: required_keys(timezone, locale)\n")
                && (request.contains("settings: { [key in string]?: string }")
                    || request.contains("settings: Record<string, string>")),
            "expected manual map validation comments to annotate generated DTO fields:\n{request}"
        );
        assert!(
            helper.contains(
                "rules: [\n    { code: \"after\", params: { \"hook\": \"validate_manual_payload\" }, serverOnly: true }\n  ]"
            ),
            "expected manual schema-level validation rules from inventory:\n{helper}"
        );
        assert!(
            helper.contains(
                "{ name: \"value\", rules: [{ code: \"required\" }, { code: \"min\", params: { \"min\": \"5\" } }] }"
            ),
            "expected manual field validation rules from inventory:\n{helper}"
        );
        assert!(
            helper.contains(
                "{ name: \"token\", rules: [{ code: \"manual_token\", serverOnly: true }] }"
            ),
            "expected manual server-only field validation metadata from inventory:\n{helper}"
        );
        assert!(
            helper.contains(
                "{ name: \"tags\", rules: [{ code: \"size\", params: { \"kind\": \"array\", \"size\": \"2\" } }] }"
            ),
            "expected manual size_items helper metadata to export canonical size metadata from inventory:\n{helper}"
        );
        assert!(
            helper.contains(
                "{ name: \"settings\", rules: [{ code: \"required_keys\", values: [\"timezone\", \"locale\"] }] }"
            ),
            "expected manual required_keys validation metadata from inventory:\n{helper}"
        );
        assert!(
            helper.contains(
                "{ field: \"value\", rule: \"required\", message: \"Value is required.\" }"
            ) && helper.contains("{ field: \"value\", name: \"manual value\" }"),
            "expected manual validation messages and attributes from inventory:\n{helper}"
        );
    }

    #[test]
    fn validation_schema_collection_rejects_duplicate_names() {
        let entries = [
            super::TsValidation {
                name: "DuplicateValidationRequest",
                schema_fn: empty_validation_schema,
            },
            super::TsValidation {
                name: "DuplicateValidationRequest",
                schema_fn: empty_validation_schema,
            },
        ];

        let error = super::collect_validation_schemas(entries.iter())
            .expect_err("duplicate validation schema names should fail");
        assert!(
            error.to_string().contains(
                "validation schema `DuplicateValidationRequest` registered multiple times"
            ),
            "unexpected error: {error}"
        );
    }

    #[test]
    fn validation_schema_lookup_rejects_duplicate_names() {
        let entries = [
            super::TsValidation {
                name: "DuplicateLookupValidationRequest",
                schema_fn: empty_validation_schema,
            },
            super::TsValidation {
                name: "DuplicateLookupValidationRequest",
                schema_fn: empty_validation_schema,
            },
        ];

        let error = super::registered_validation_schema_from(
            entries.iter(),
            "DuplicateLookupValidationRequest",
        )
        .expect_err("duplicate validation schema lookup should fail");
        assert!(
            error.to_string().contains(
                "validation schema `DuplicateLookupValidationRequest` registered multiple times"
            ),
            "unexpected error: {error}"
        );
    }

