    #[test]
    fn validation_schema_collection_allows_server_only_rule_helpers() {
        let entries = [super::TsValidation {
            name: "ServerOnlyRuleHelpersRequest",
            schema_fn: server_only_rule_helpers_validation_schema,
        }];

        let schemas = super::collect_validation_schemas(entries.iter())
            .expect("server-only helper rules should emit exportable metadata");

        let schema = schemas.get("ServerOnlyRuleHelpersRequest").unwrap();
        assert_eq!(schema.rules[0].code, "after");
        assert_eq!(schema.rules[0].params["hook"], "validate_manual_payload");
        assert!(schema.rules[0].server_only);

        let email_rule = |code: &str| {
            schema.fields[0]
                .rules
                .iter()
                .find(|rule| rule.code == code)
                .unwrap_or_else(|| panic!("missing `{code}` email rule"))
        };
        assert_eq!(email_rule("unique").params["table"], "users");
        assert_eq!(email_rule("unique").params["column"], "email");
        assert!(email_rule("unique").server_only);
        assert_eq!(email_rule("exists").params["table"], "contacts");
        assert_eq!(email_rule("exists").params["column"], "email");
        assert!(email_rule("exists").server_only);

        let avatar_rule = |code: &str| {
            schema.fields[1]
                .rules
                .iter()
                .find(|rule| rule.code == code)
                .unwrap_or_else(|| panic!("missing `{code}` avatar rule"))
        };
        assert!(avatar_rule("image").server_only);
        assert_eq!(
            avatar_rule("allowed_mimes").values,
            vec!["image/png", "image/jpeg"]
        );
        assert!(avatar_rule("allowed_mimes").server_only);
        assert_eq!(avatar_rule("max_dimensions").params["width"], "1024");
        assert_eq!(avatar_rule("max_dimensions").params["height"], "768");
        assert!(avatar_rule("max_dimensions").server_only);
        assert_eq!(avatar_rule("min_dimensions").params["width"], "128");
        assert_eq!(avatar_rule("min_dimensions").params["height"], "128");
        assert!(avatar_rule("min_dimensions").server_only);

        let custom_rule = schema.fields[2]
            .rules
            .iter()
            .find(|rule| rule.code == MOBILE_RULE_ID.as_str())
            .expect("missing custom rule helper metadata");
        assert_eq!(custom_rule.params["rule"], MOBILE_RULE_ID.as_str());
        assert!(custom_rule.server_only);
    }

