    #[test]
    fn validation_schema_collection_allows_no_arg_rule_helpers() {
        let entries = [super::TsValidation {
            name: "NoArgRuleHelpersRequest",
            schema_fn: no_arg_rule_helpers_validation_schema,
        }];

        let schemas = super::collect_validation_schemas(entries.iter())
            .expect("no-arg helper rules should emit canonical validation metadata");

        let schema = schemas.get("NoArgRuleHelpersRequest").unwrap();
        let codes = |field: &str| {
            schema
                .fields
                .iter()
                .find(|entry| entry.name == field)
                .unwrap_or_else(|| panic!("missing helper field `{field}`"))
                .rules
                .iter()
                .map(|rule| rule.code.as_str())
                .collect::<Vec<_>>()
        };

        assert_eq!(codes("email"), vec!["required", "bail", "filled", "email"]);
        assert_eq!(codes("link"), vec!["nullable", "url"]);
        assert_eq!(codes("identifier"), vec!["uuid", "ulid"]);
        assert_eq!(
            codes("label"),
            vec![
                "alpha",
                "alpha_dash",
                "alpha_num",
                "alpha_numeric",
                "ascii",
                "lowercase",
                "uppercase",
                "hex_color",
                "mac_address",
            ]
        );
        assert_eq!(codes("amount"), vec!["numeric", "integer", "digits"]);
        assert_eq!(
            codes("choice"),
            vec!["boolean", "accepted", "declined", "prohibited"]
        );
        assert_eq!(
            codes("starts_at"),
            vec!["date", "time", "datetime", "local_datetime", "timezone"]
        );
        assert_eq!(codes("network"), vec!["ip", "ipv4", "ipv6"]);
        assert_eq!(codes("payload"), vec!["json"]);
        assert_eq!(codes("tags"), vec!["distinct", "each"]);
        assert_eq!(
            schema
                .fields
                .iter()
                .find(|entry| entry.name == "tags")
                .unwrap()
                .rules[1]
                .rules[0]
                .code,
            "required"
        );
        assert_eq!(codes("profile"), vec!["nested"]);
        assert_eq!(
            schema
                .fields
                .iter()
                .find(|entry| entry.name == "profile")
                .unwrap()
                .rules[0]
                .schema
                .as_ref()
                .expect("nested schema")
                .fields[0]
                .rules[0]
                .code,
            "required"
        );
    }

