    #[test]
    fn validation_schema_collection_allows_field_reference_rule_helpers() {
        let entries = [super::TsValidation {
            name: "FieldReferenceRuleHelpersRequest",
            schema_fn: field_reference_rule_helpers_validation_schema,
        }];

        let schemas = super::collect_validation_schemas(entries.iter())
            .expect("field-reference rule helpers should emit consistent params");

        let schema = schemas.get("FieldReferenceRuleHelpersRequest").unwrap();
        let expected = [
            ("terms", "accepted_if", "newsletter", Some("yes")),
            ("terms", "declined_if", "archived", Some("true")),
            ("display_name", "required_if", "enabled", Some("true")),
            ("display_name", "required_unless", "mode", Some("draft")),
            ("display_name", "required_with", "guest_reason", None),
            ("display_name", "required_without", "fallback_name", None),
            ("approval", "required_if_accepted", "terms", None),
            ("approval", "required_if_declined", "marketing", None),
            ("admin_note", "prohibited_if", "role", Some("admin")),
            ("admin_note", "prohibited_unless", "mode", Some("safe")),
            ("admin_note", "prohibited_if_accepted", "terms", None),
            ("admin_note", "prohibited_if_declined", "marketing", None),
            (
                "new_password",
                "confirmed",
                "new_password_confirmation",
                None,
            ),
            ("new_password", "same", "password_repeat", None),
            ("new_password", "different", "current_password", None),
            ("publish_at", "before", "expires_at", None),
            ("publish_at", "before_or_equal", "deadline", None),
            ("publish_at", "after", "starts_at", None),
            ("publish_at", "after_or_equal", "release_at", None),
            ("publish_at", "date_equals", "expected_publish_at", None),
        ];

        for (field, code, other, value) in expected {
            let rule = schema
                .fields
                .iter()
                .find(|entry| entry.name == field)
                .and_then(|entry| entry.rules.iter().find(|rule| rule.code == code))
                .unwrap_or_else(|| panic!("missing helper rule `{code}` on `{field}`"));
            assert_eq!(rule.params["other"], other);
            assert_eq!(rule.params.get("value").map(String::as_str), value);
        }
    }

    #[test]
    fn validation_schema_collection_allows_scalar_rule_helpers() {
        let entries = [super::TsValidation {
            name: "ScalarRuleHelpersRequest",
            schema_fn: scalar_rule_helpers_validation_schema,
        }];

        let schemas = super::collect_validation_schemas(entries.iter())
            .expect("scalar rule helpers should emit verifier-compatible params and values");

        let schema = schemas.get("ScalarRuleHelpersRequest").unwrap();
        let rule = |field: &str, code: &str| {
            schema
                .fields
                .iter()
                .find(|entry| entry.name == field)
                .and_then(|entry| entry.rules.iter().find(|rule| rule.code == code))
                .unwrap_or_else(|| panic!("missing helper rule `{code}` on `{field}`"))
        };

        assert_eq!(rule("title", "min").params["min"], "3");
        assert_eq!(rule("title", "max").params["max"], "120");
        assert_eq!(rule("title", "size").params["size"], "10");
        assert_eq!(rule("title", "starts_with").values, vec!["doc.", "guide."]);
        assert_eq!(rule("title", "starts_with").params["value"], "doc., guide.");
        assert_eq!(
            rule("title", "doesnt_start_with").params["value"],
            "tmp., old."
        );
        assert_eq!(rule("title", "ends_with").params["value"], ".md, .mdx");
        assert_eq!(rule("title", "doesnt_end_with").params["value"], ".bak");
        assert_eq!(rule("title", "contains").params["value"], "foundry, rust");
        assert_eq!(rule("title", "doesnt_contain").params["value"], "legacy");
        assert_eq!(rule("title", "regex").params["pattern"], r"^[a-z0-9._-]+$");
        assert_eq!(rule("title", "not_regex").params["pattern"], r"^legacy");
        assert_eq!(rule("title", "in_list").values, vec!["draft", "published"]);
        assert_eq!(rule("title", "not_in").values, vec!["archived"]);
        assert_eq!(rule("alias_title", "min").params["min"], "3");
        assert_eq!(rule("alias_title", "max").params["max"], "120");
        assert_eq!(
            rule("alias_title", "starts_with").values,
            vec!["guide.", "manual."]
        );
        assert_eq!(
            rule("alias_title", "doesnt_start_with").params["value"],
            "draft., tmp."
        );
        assert_eq!(
            rule("alias_title", "ends_with").params["value"],
            ".md, .txt"
        );
        assert_eq!(
            rule("alias_title", "doesnt_end_with").values,
            vec![".bak", ".old"]
        );
        for (code, value) in [
            ("starts_with", "doc."),
            ("doesnt_start_with", "tmp."),
            ("ends_with", ".md"),
            ("doesnt_end_with", ".bak"),
            ("contains", "foundry"),
            ("doesnt_contain", "legacy"),
        ] {
            let helper_rule = rule("slug", code);
            assert_eq!(helper_rule.params["value"], value);
            assert!(helper_rule.values.is_empty());
        }

        assert_eq!(rule("amount", "min_numeric").params["min"], "-1.5");
        assert_eq!(rule("amount", "max_numeric").params["max"], "99.5");
        assert_eq!(rule("amount", "between").params["min"], "-1.5");
        assert_eq!(rule("amount", "between").params["max"], "99.5");
        assert_eq!(rule("amount", "multiple_of").params["value"], "0.5");
        assert_eq!(rule("amount", "gt").params["value"], "0");
        assert_eq!(rule("amount", "gte").params["value"], "1");
        assert_eq!(rule("amount", "lt").params["value"], "100");
        assert_eq!(rule("amount", "lte").params["value"], "99");
        assert_eq!(rule("amount", "size").params["size"], "42.5");
        assert_eq!(rule("amount", "decimal").params["min"], "2");
        assert_eq!(rule("amount", "decimal").params["max"], "4");

        assert_eq!(rule("pin", "min_digits").params["min"], "4");
        assert_eq!(rule("pin", "max_digits").params["max"], "6");
        assert_eq!(rule("pin", "digits_between").params["min"], "4");
        assert_eq!(rule("pin", "digits_between").params["max"], "6");

        assert_eq!(rule("tags", "min_items").params["min"], "1");
        assert_eq!(rule("tags", "max_items").params["max"], "5");
        assert_eq!(rule("avatar", "max_file_size").params["max"], "2048");
        assert_eq!(
            rule("avatar", "allowed_extensions").values,
            vec!["jpg", "png"]
        );
        assert_eq!(rule("request_id", "uuid").params["version"], "4");
    }

