    #[test]
    fn rust_regex_client_compatibility_matches_generated_runtime_surface() {
        assert!(super::rust_regex_is_client_compatible("admin"));
        assert!(super::rust_regex_is_client_compatible(r"(?i)^foundry$"));
        assert!(super::rust_regex_is_client_compatible(r"(?P<slug>[a-z]+)"));

        assert!(!super::rust_regex_is_client_compatible("["));
        assert!(!super::rust_regex_is_client_compatible(r"(?x)^ admin $"));
        assert!(!super::rust_regex_is_client_compatible(r"(?i:admin)"));
        assert!(!super::rust_regex_is_client_compatible(r"\Aadmin\z"));
    }

    #[test]
    fn validation_schema_builder_merges_duplicate_fields() {
        let schema = super::TsValidationSchema::new()
            .field("email", [super::TsValidationRule::required()])
            .field("email", [super::TsValidationRule::email()]);

        assert_eq!(schema.fields.len(), 1);
        assert_eq!(schema.fields[0].name, "email");
        assert_eq!(
            schema.fields[0]
                .rules
                .iter()
                .map(|rule| rule.code.as_str())
                .collect::<Vec<_>>(),
            vec!["required", "email"]
        );
    }

    #[test]
    fn validation_schema_builder_enables_strict_unknown_field_metadata() {
        let schema = super::TsValidationSchema::new()
            .deny_unknown_fields()
            .known_fields(["name", "nickname", "name"]);

        assert!(schema.deny_unknown_fields);
        assert_eq!(schema.known_fields, vec!["name", "nickname"]);

        let schema = super::TsValidationSchema::new()
            .deny_unknown_fields_with_known_fields(["email", "token", "email"]);

        assert!(schema.deny_unknown_fields);
        assert_eq!(schema.known_fields, vec!["email", "token"]);
    }

    #[test]
    fn validation_schema_builder_tracks_non_scalar_reference_value_kinds() {
        let schema = super::TsValidationSchema::new()
            .field_value_kind("attachments", super::TsValidationFieldValueKind::Array)
            .field_value_kind("settings", super::TsValidationFieldValueKind::Map)
            .field_value_kind("settings", super::TsValidationFieldValueKind::Json);

        assert_eq!(schema.field_value_kinds.len(), 2);
        assert_eq!(schema.field_value_kinds[0].field, "attachments");
        assert_eq!(
            schema.field_value_kinds[0].kind,
            super::TsValidationFieldValueKind::Array
        );
        assert_eq!(schema.field_value_kinds[1].field, "settings");
        assert_eq!(
            schema.field_value_kinds[1].kind,
            super::TsValidationFieldValueKind::Json
        );

        let schema = schema.field_value_kind("settings", super::TsValidationFieldValueKind::Scalar);

        assert_eq!(
            schema
                .field_value_kinds
                .iter()
                .map(|entry| entry.field.as_str())
                .collect::<Vec<_>>(),
            vec!["attachments"]
        );
    }

    #[test]
    fn validation_schema_builder_replaces_duplicate_messages_and_attributes() {
        let schema = super::TsValidationSchema::new()
            .message("email", "required", "Email required.")
            .message("email", "required", "Please enter an email.")
            .attribute("email", "email address")
            .attribute("email", "work email");

        assert_eq!(schema.messages.len(), 1);
        assert_eq!(schema.messages[0].field, "email");
        assert_eq!(schema.messages[0].rule, "required");
        assert_eq!(schema.messages[0].message, "Please enter an email.");
        assert_eq!(schema.attributes.len(), 1);
        assert_eq!(schema.attributes[0].field, "email");
        assert_eq!(schema.attributes[0].name, "work email");
    }

    #[test]
    fn validation_schema_builder_deduplicates_exact_rules_and_values() {
        let min_rule = super::TsValidationRule::new("min").param("min", 3);
        let schema = super::TsValidationSchema::new()
            .rule(min_rule.clone())
            .rule(min_rule.clone())
            .rule(super::TsValidationRule::new("min").param("min", 5));

        assert_eq!(schema.rules.len(), 2);
        assert_eq!(schema.rules[0].params["min"], "3");
        assert_eq!(schema.rules[1].params["min"], "5");

        let nested_rule = super::TsValidationRule::required();
        let rule = super::TsValidationRule::each([nested_rule.clone()])
            .value("email")
            .value("email")
            .values(["name", "email"])
            .nested_rule(nested_rule.clone())
            .nested_rules([super::TsValidationRule::email()]);

        assert_eq!(rule.values, vec!["email", "name"]);
        assert_eq!(
            rule.rules
                .iter()
                .map(|rule| rule.code.as_str())
                .collect::<Vec<_>>(),
            vec!["required", "email"]
        );

        let required_keys =
            super::TsValidationRule::required_keys(["timezone", "timezone", "locale"]);
        assert_eq!(required_keys.code, "required_keys");
        assert_eq!(required_keys.values, vec!["timezone", "locale"]);
    }

    #[test]
    fn prelude_exports_manual_validation_metadata_builders() {
        use crate::prelude::{
            ChannelEventId, ChannelId, EventId, JobId, TsEventPayload, TsJobPayload, TsValidation,
            TsValidationAttribute, TsValidationField, TsValidationFieldValueKind,
            TsValidationFieldValueKindEntry, TsValidationMessage, TsValidationRule,
            TsValidationSchema, TsValidationSchemaProvider, TsWebSocketPayload,
            TsWebSocketPayloadDirection,
        };

        struct PreludeValidationRequest;

        impl TsValidationSchemaProvider for PreludeValidationRequest {
            fn ts_validation_schema() -> TsValidationSchema {
                TsValidationSchema::new().field("email", [TsValidationRule::required()])
            }
        }

        let registration = TsValidation {
            name: "PreludeValidationRequest",
            schema_fn: || {
                <PreludeValidationRequest as TsValidationSchemaProvider>::ts_validation_schema()
            },
        };
        let schema = (registration.schema_fn)()
            .message("email", "required", "Email required.")
            .attribute("email", "email");
        let _field = TsValidationField::new("name", [TsValidationRule::filled()]);
        let _message = TsValidationMessage {
            field: "name".to_string(),
            rule: "filled".to_string(),
            message: "Name required.".to_string(),
        };
        let _attribute = TsValidationAttribute {
            field: "name".to_string(),
            name: "full name".to_string(),
        };
        let _field_value_kind = TsValidationFieldValueKindEntry {
            field: "attachments".to_string(),
            kind: TsValidationFieldValueKind::Array,
        };
        let _websocket_payload = TsWebSocketPayload::server(
            ChannelId::new("chat.rooms"),
            ChannelEventId::new("message"),
            "PreludeValidationRequest",
        );
        let _job_payload =
            TsJobPayload::new(JobId::new("mail.welcome"), "PreludeValidationRequest");
        let _event_payload =
            TsEventPayload::new(EventId::new("orders.placed"), "PreludeValidationRequest");

        assert_eq!(schema.fields[0].name, "email");
        assert_eq!(schema.fields[0].rules[0].code, "required");
        assert_eq!(schema.messages[0].message, "Email required.");
        assert_eq!(schema.attributes[0].name, "email");
        assert_eq!(
            _websocket_payload.direction,
            TsWebSocketPayloadDirection::Server
        );
        assert_eq!(_field_value_kind.kind, TsValidationFieldValueKind::Array);
        assert_eq!(_job_payload.payload, "PreludeValidationRequest");
        assert_eq!(_event_payload.payload, "PreludeValidationRequest");
    }

    #[test]
    fn exports_nested_validation_metadata() {
        let dir = tempdir().unwrap();
        export_all_with_routes(dir.path(), &[nested_profile_route_manifest_entry()]).unwrap();

        let runtime = fs::read_to_string(dir.path().join("FoundryEndpoint.ts")).unwrap();
        let helper = fs::read_to_string(dir.path().join("routes/ProfilesNestedStore.ts")).unwrap();
        let request = fs::read_to_string(dir.path().join("NestedProfileRequest.ts")).unwrap();
        let nested_request =
            fs::read_to_string(dir.path().join("NestedAddressRequest.ts")).unwrap();

        assert!(
            runtime.contains("if (foundryValidationRuleIsNested(rule))")
                && runtime.contains("const nestedSchema = foundryValidationRuleSchema(rule);")
                && runtime.contains("validateFoundryRecord(\n          nestedSchema")
                && runtime.contains("if (foundryValidationRuleIsEach(rule))")
                && runtime.contains("foundryValidationRuleNestedRules(rule)")
                && runtime.contains("(nestedField) => `${field}.${nestedField}`")
                && runtime.contains("function foundryValidationSchemaReachableRuleRows<TRequest>")
                && runtime.contains("export function foundryValidationSchemaReachableRules<TRequest>")
                && runtime.contains("export function foundryValidationSchemaReachableRuleCodes<TRequest>")
                && runtime.contains("export function foundryValidationSchemaReachableRulesWithCode<TRequest>")
                && runtime.contains("function foundryValidationSchemaReachableFieldRows<TRequest>")
                && runtime.contains("export function foundryValidationSchemaReachableFields<TRequest>")
                && runtime.contains("export function foundryValidationSchemaReachableFieldNames<TRequest>")
                && runtime.contains("function foundryValidationSchemaReachableMessages<TRequest>")
                && runtime.contains("function foundryValidationSchemaReachableAttributes<TRequest>")
                && runtime.contains("function foundryValidationTouchedFieldNames<TRequest>")
                && runtime.contains("function foundryValidationSchemaFieldsWithReachableRules<TRequest>")
                && runtime.contains("function foundryValidationFieldReferenceName(field: string, reference: string): string")
                && runtime.contains("const directField = foundryValidationSchemaFields(schema).find((entry) => entry.name === field);")
                && runtime.contains("foundryValidationSchemaReachableField(schema, field) as FoundryValidationField<FoundryRequestField<TRequest>> | undefined")
                && runtime.contains("const concreteField = foundryValidationDependentFieldName(String(field), String(entry.name));")
                && runtime.contains("return foundryValidationSchemaReachableFieldRows(schema).filter((field) =>")
                && runtime.contains("field: foundryValidationChildFieldName(parent, String(entry.field))")
                && runtime.contains("return validationMessage(foundryValidationSchemaReachableMessages(schema), field, rule);")
                && runtime.contains("validationAttributeName(foundryValidationSchemaReachableAttributes(schema), field)")
                && runtime.contains("for (const field of foundryValidationSchemaReachableFieldNames(schema))")
                && runtime.contains("...foundryValidationSchemaReachableFieldNames(schema),")
                && runtime.contains("...foundryValidationTouchedFieldNames(result),")
                && runtime.contains("return foundryValidationSchemaFieldsWithReachableRules(schema, foundryValidationRuleIsRequired);")
                && runtime.contains("return foundryValidationSchemaFieldsWithReachableRules(schema, (rule) => rule.code === code);"),
            "expected endpoint runtime to recurse into nested DTO validation schemas:\n{runtime}"
        );
        assert!(
            request.contains("// Validation: nested\n")
                && request.contains("primaryAddress: NestedAddressRequest")
                && request.contains("// Validation: min_items(1), each(nested)\n")
                && request.contains("previousAddresses: Array<NestedAddressRequest>"),
            "expected nested validation comments and serde wire field names:\n{request}"
        );
        assert!(
            nested_request.contains("// Validation: confirmed(accessCodeConfirmation)\n"),
            "expected nested child validation comments to use serde wire sibling names:\n{nested_request}"
        );
        assert!(
            helper.contains("{ name: \"primaryAddress\", rules: [{ code: \"nested\", schema: {")
                && helper.contains("{ name: \"streetName\", rules: [{ code: \"required\" }] }")
                && helper.contains("{ name: \"postalCode\", rules: [{ code: \"required\" }] }")
                && helper.contains("{ name: \"accessCode\", rules: [{ code: \"confirmed\", params: { \"other\": \"accessCodeConfirmation\" } }] }"),
            "expected direct nested field to embed child validation schema:\n{helper}"
        );
        assert!(
            helper.contains(
                "{ name: \"previousAddresses\", rules: [{ code: \"min_items\", params: { \"min\": \"1\" } }, { code: \"each\", rules: [{ code: \"nested\", schema: {"
            ),
            "expected each(nested) field to embed child validation schema:\n{helper}"
        );
        assert!(
            helper.contains(
                "{ field: \"streetName\", rule: \"required\", message: \"Street is required.\" }"
            ) && helper.contains("{ field: \"streetName\", name: \"street name\" }"),
            "expected nested child messages and attributes to stay keyed to the child schema:\n{helper}"
        );
    }

    #[test]
    fn exports_route_endpoint_helper_binds_path_params_at_factory() {
        let dir = tempdir().unwrap();
        let mut route =
            route_manifest_entry("admin.users.show", "/api/v1/admin/users/{id}", &["id"]);
        route.request = None;
        route.request_transport = None;

        export_all_with_routes(dir.path(), &[route]).unwrap();

        let helper = fs::read_to_string(dir.path().join("routes/AdminUsersShow.ts")).unwrap();
        assert!(
            helper.contains("export type AdminUsersShowRequest = Record<string, never>;"),
            "expected no-request route helper to keep the empty request alias:\n{helper}"
        );
        assert!(
            helper.contains("export type AdminUsersShowParams = { \"id\": RouteParamValue };"),
            "expected route path params to be exported as a typed helper alias:\n{helper}"
        );
        assert!(
            helper.contains(
                "export function AdminUsersShow(client: FoundryHttpClient, params: AdminUsersShowParams, data: AdminUsersShowRequest = {}): AdminUsersShowEndpoint"
            ),
            "expected path params to be required at route helper construction while request data keeps its default:\n{helper}"
        );
        assert!(
            helper.contains("return new AdminUsersShowEndpoint(client, data, params);"),
            "expected generated helper to bind params onto the endpoint instance:\n{helper}"
        );
    }

