                && rendered.contains("export function routeIsDeprecated<Name extends RouteName>")
                && rendered.contains("export function routeHasDocumentMetadata<Name extends RouteName>")
                && rendered.contains("export function routeHasGuard<Name extends RouteName>")
                && rendered.contains("export function routeParamCount<Name extends RouteName>")
                && rendered.contains("export function routeHasParam<Name extends RouteName>")
