                && rendered.contains("export function routeFirstPermission<Name extends RouteName>")
                && rendered.contains("export function routeTagCount<Name extends RouteName>")
                && rendered.contains("export function routeHasTags<Name extends RouteName>")
                && rendered.contains("export function routeFirstTag<Name extends RouteName>")
                && rendered.contains("export function deprecatedRoutes(): RouteManifestEntry[]")
