                && rendered.contains("export function authRequiredRouteCount(): number")
                && rendered.contains("export function routeHasAuthRequiredRoutes(): boolean")
                && rendered
                    .contains("export function firstAuthRequiredRoute(): RouteManifestEntry | undefined")
                && rendered
