    #[test]
    fn route_manifest_schema_wrappers_are_shared_by_validation_and_type_resolution() {
        assert_eq!(
            route_manifest_schema_wrapper_names(),
            "Array, Map, Nullable, PaginatedResponse, CursorPaginated, Collection"
        );
        assert_eq!(
            supported_route_manifest_schema_wrapper_inner("Map<Array<UserResponse>>"),
            Some((RouteManifestSchemaWrapper::Map, "Array<UserResponse>"))
        );

        let mut exported_types = BTreeMap::new();
        exported_types.insert("UserResponse".to_string(), "UserResponse".to_string());

        for (schema, expected_type) in [
            ("Array<UserResponse>", "UserResponse[]"),
            ("Map<UserResponse>", "Record<string, UserResponse>"),
            ("Nullable<UserResponse>", "UserResponse | null"),
            (
                "PaginatedResponse<UserResponse>",
                "{ data: UserResponse[]; meta: PaginationMeta; links: PaginationLinks }",
            ),
            (
                "CursorPaginated<UserResponse>",
                "{ data: UserResponse[]; meta: CursorMeta; cursors: CursorInfo }",
            ),
            ("Collection<UserResponse>", "{ items: UserResponse[] }"),
        ] {
            ensure_route_manifest_schema_expression("users.index", "response", schema).unwrap();

            let mut imports = BTreeSet::new();
            let actual_type =
                schema_type_reference(Some(schema), &exported_types, &mut imports, "never")
                    .unwrap();

            assert_eq!(
                actual_type, expected_type,
                "schema wrapper {schema} should resolve through the shared wrapper descriptor"
            );
        }
    }

