    #[test]
    fn app_enum_groups_are_not_rendered_for_plain_string_enums() {
        let rendered = render_app_enum("PlainStatus", &string_meta(&["pending", "completed"]))
            .expect("plain string enums should render");

        assert!(rendered.has_keys);
        assert!(!rendered.has_groups);
        assert!(
            rendered
                .content
                .contains("export const PlainStatusKeys = freezePlainStatusEnumValue({"),
            "expected key constants for non-dotted string enum:\n{}",
            rendered.content
        );
        assert!(
            !rendered.content.contains("PlainStatusGroups"),
            "did not expect groups for non-dotted string enum:\n{}",
            rendered.content
        );
        assert!(
            rendered.content.contains(
                "export function parsePlainStatusOrNull(value: unknown): PlainStatus | null"
            ) && rendered.content.contains(
                "return isPlainStatus(value) ? value : getPlainStatusAliasTargetOrNull(value);"
            ),
            "expected safe parser companion for AppEnum guard:\n{}",
            rendered.content
        );
    }

    #[test]
    fn app_enum_alias_metadata_normalizes_to_canonical_values() {
        let meta = EnumMeta {
            id: "legacy_status".to_string(),
            key_kind: EnumKeyKind::String,
            options: Collection::from(vec![
                app_enum_string_option_with_aliases(
                    "pending",
                    "enum.legacy_status.pending",
                    &["awaiting", "queued"],
                ),
                app_enum_string_option("completed", "enum.legacy_status.completed"),
            ]),
        };

        let rendered = render_app_enum("LegacyStatus", &meta).unwrap();

        assert!(
            rendered.content.contains(
                "{ value: \"pending\", labelKey: \"enum.legacy_status.pending\", aliases: [\"awaiting\", \"queued\"] }"
            ) && rendered.content.contains(
                "export const LegacyStatusAliases = freezeLegacyStatusEnumValue({"
            ) && rendered.content.contains("\"awaiting\": \"pending\"")
                && rendered.content.contains("\"queued\": \"pending\"")
                && rendered
                    .content
                    .contains("export type LegacyStatusAlias = keyof typeof LegacyStatusAliases;")
                && rendered
                    .content
                    .contains("export function getLegacyStatusAliases(): typeof LegacyStatusAliases")
                && rendered
                    .content
                    .contains("export function isLegacyStatusAlias(value: unknown): value is LegacyStatusAlias")
                && rendered
                    .content
                    .contains("export function getLegacyStatusAliasTarget(value: LegacyStatusAlias): LegacyStatus")
                && rendered
                    .content
                    .contains("export function getLegacyStatusCanonicalValue(value: LegacyStatus | LegacyStatusAlias): LegacyStatus")
                && rendered
                    .content
                    .contains("return isLegacyStatus(value) ? value : getLegacyStatusAliasTarget(value);")
                && rendered
                    .content
                    .contains("return isLegacyStatus(value) ? value : getLegacyStatusAliasTargetOrNull(value);"),
            "expected AppEnum aliases to be exported and parsed to canonical values:\n{}",
            rendered.content
        );
    }

